"use strict";(self.webpackChunkmagento2_hyva_jewellery_theme_docs=self.webpackChunkmagento2_hyva_jewellery_theme_docs||[]).push([[4117],{6936(t,e,n){n.r(e),n.d(e,{comp:()=>s,data:()=>l});var o=n(641);const r={},s=(0,n(6262).A)(r,[["render",function(t,e){return(0,o.uX)(),(0,o.CE)("div",null,[...e[0]||(e[0]=[(0,o.Fv)('<h1 id="collection-banners" tabindex="-1"><a class="header-anchor" href="#collection-banners"><span>Collection Banners</span></a></h1><p>The <strong>Collection Banners</strong> section shows two or more image banners on the homepage. Use it for bridal collections, gift edits, seasonal offers, or premium jewellery ranges.</p><h2 id="add-collection-banners" tabindex="-1"><a class="header-anchor" href="#add-collection-banners"><span>Add Collection Banners</span></a></h2><ol><li>Go to <strong>Content -&gt; Homepage Configurator -&gt; Sections</strong>.</li><li>Click <strong>Add New Section</strong>.</li><li>Enter a <strong>Title</strong>, for example <code>Collection Stories</code>.</li><li>Set <strong>Section Type</strong> to <strong>Collection Banners</strong>.</li><li>Set <strong>Enabled</strong> to <strong>Yes</strong>.</li><li>Use a <strong>Sort Order</strong> so it appears in the right place on the homepage.</li><li>Fill the <strong>Collection Banner Configuration</strong> fields.</li><li>Click <strong>Save</strong>.</li></ol><h2 id="main-settings" tabindex="-1"><a class="header-anchor" href="#main-settings"><span>Main settings</span></a></h2><table><thead><tr><th>Setting</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Layout</strong></td><td>Choose <strong>Side by Side</strong> for two columns, or <strong>Stacked</strong> for one column.</td></tr><tr><td><strong>Banners</strong></td><td>Add the banner cards that shoppers will see.</td></tr></tbody></table><h2 id="banner-fields" tabindex="-1"><a class="header-anchor" href="#banner-fields"><span>Banner fields</span></a></h2><p>Click <strong>Add Banner</strong>, then fill these fields.</p><table><thead><tr><th>Field</th><th>What to enter</th></tr></thead><tbody><tr><td><strong>Banner Image</strong></td><td>Upload a clear image. Recommended size is <strong>900 x 600 px</strong>. Maximum file size is <strong>4 MB</strong>.</td></tr><tr><td><strong>Title</strong></td><td>Main banner text, such as <code>Diamond Rings</code>.</td></tr><tr><td><strong>Subtitle</strong></td><td>Short text below the title.</td></tr><tr><td><strong>Button Label</strong></td><td>Button text, such as <code>Shop Now</code>.</td></tr><tr><td><strong>Button URL</strong></td><td>Category or collection link, such as <code>/jewelry/rings.html</code>.</td></tr></tbody></table><h2 id="storefront-result" tabindex="-1"><a class="header-anchor" href="#storefront-result"><span>Storefront result</span></a></h2><p><img src="/screenshots/collection-banners-storefront-result.png" alt="Collection banners on the storefront"></p><h2 id="good-practice" tabindex="-1"><a class="header-anchor" href="#good-practice"><span>Good practice</span></a></h2><ul><li>Use two banners when both collections are equally important.</li><li>Keep the title short.</li><li>Use images with a similar color tone.</li><li>Link each banner to the matching category or collection page.</li></ul>',13)])])}]]),l=JSON.parse('{"path":"/homepage/collection-banners.html","title":"Collection Banners","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Add Collection Banners","slug":"add-collection-banners","link":"#add-collection-banners","children":[]},{"level":2,"title":"Main settings","slug":"main-settings","link":"#main-settings","children":[]},{"level":2,"title":"Banner fields","slug":"banner-fields","link":"#banner-fields","children":[]},{"level":2,"title":"Storefront result","slug":"storefront-result","link":"#storefront-result","children":[]},{"level":2,"title":"Good practice","slug":"good-practice","link":"#good-practice","children":[]}],"git":{},"filePathRelative":"homepage/collection-banners.md"}')}}]);